    async getDetail() {
      try {
        let res = await $axios.get("product/detail", this.$route.params);
        // console.log(this.$route.params)
        
        if (res.code == 666) {
          this.productInfo = res.result;
        } else {
          this.$toast.fail(res.msg);
        }
      } catch (error) {
        this.$toast.fail(error);
      }
    },
    async getCartNum(){
      if(!this.isLogin) return false
      try {
        let res= await $axios.get('cart/all')
        // console.log(res)
        let sum=0
        res.list.forEach(item=>{
          sum+=item.buyNum
        })
        // console.log(sum)
        this.$store.commit('setNum',sum)
        // console.log(this.$store.state.cart.cartNum)
      } catch (err) {
